                col = col-1;
            }

            if(	row > (common.in2_pad_add_rows-1) &&
                row < (common.in2_pad_add_rows+common.in2_rows) && 
                col > (common.in2_pad_add_cols-1) && 
                col < (common.in2_pad_add_cols+common.in2_cols)){
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                unique[bx].d_in2_pad_cumv[ei_new] = unique[bx].d_in2[ori_col*common.in2_rows+ori_row];
            }
            else{
                unique[bx].d_in2_pad_cumv[ei_new] = 0;
            }
        }

        for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
            pos_ori = ei_new*common.in2_pad_cumv_rows;
            sum = 0;
            for(position = pos_ori; position < pos_ori+common.in2_pad_cumv_rows; position += 1){
                unique[bx].d_in2_pad_cumv[position] = unique[bx].d_in2_pad_cumv[position] + sum;
                sum = unique[bx].d_in2_pad_cumv[position];
            }
        }

        for(ei_new = 0; ei_new < common.in2_pad_cumv_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_sel_rows == 0){
                row = common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            unique[bx].d_in2_pad_cumv_sel[ei_new] = unique[bx].d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_rows == 0){
                row = common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            unique[bx].d_in2_sub_cumh[ei_new] = unique[bx].d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            unique[bx].d_in2_sub_cumh[ei_new] = unique[bx].d_in2_pad_cumv_sel[ei_new] - unique[bx].d_in2_sub_cumh[ei_new];
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for(position = pos_ori; position < pos_ori+common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows){
                unique[bx].d_in2_sub_cumh[position] = unique[bx].d_in2_sub_cumh[position] + sum;
                sum = unique[bx].d_in2_sub_cumh[position];
            }
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_sel_rows == 0){
                row = common.in2_sub_cumh_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            unique[bx].d_in2_sub_cumh_sel[ei_new] = unique[bx].d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub2_rows - 1;
            col = (ei_new+1) / common.in2_sub2_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub2_rows == 0){
                row = common.in2_sub2_rows - 1;
                col = col-1;
            }

            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            unique[bx].d_in2_sub2[ei_new] = unique[bx].d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            unique[bx].d_in2_sub2[ei_new] = unique[bx].d_in2_sub_cumh_sel[ei_new] - unique[bx].d_in2_sub2[ei_new];
        }

        for(ei_new = 0; ei_new < common.in2_sqr_elem; ei_new++) {
            temp = unique[bx].d_in2[ei_new];
            unique[bx].d_in2_sqr[ei_new] = temp * temp;
        }

        for(ei_new = 0; ei_new < common.in2_pad_cumv_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_rows == 0){
                row = common.in2_pad_cumv_rows - 1;
                col = col-1;
            }

            if(	row > (common.in2_pad_add_rows-1) &&
                row < (common.in2_pad_add_rows+common.in2_sqr_rows) && 
                col > (common.in2_pad_add_cols-1) && 
                col < (common.in2_pad_add_cols+common.in2_sqr_cols)){
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                unique[bx].d_in2_pad_cumv[ei_new] = unique[bx].d_in2_sqr[ori_col*common.in2_sqr_rows+ori_row];
            }
            else{
                unique[bx].d_in2_pad_cumv[ei_new] = 0;
            }
        }

        for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
            pos_ori = ei_new*common.in2_pad_cumv_rows;
            sum = 0;
            for(position = pos_ori; position < pos_ori+common.in2_pad_cumv_rows; position += 1){
                unique[bx].d_in2_pad_cumv[position] = unique[bx].d_in2_pad_cumv[position] + sum;
                sum = unique[bx].d_in2_pad_cumv[position];
            }
        }

        for(ei_new = 0; ei_new < common.in2_pad_cumv_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_sel_rows == 0){
                row = common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            unique[bx].d_in2_pad_cumv_sel[ei_new] = unique[bx].d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_rows == 0){
                row = common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            unique[bx].d_in2_sub_cumh[ei_new] = unique[bx].d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_elem; ei_new++) {
            unique[bx].d_in2_sub_cumh[ei_new] = unique[bx].d_in2_pad_cumv_sel[ei_new] - unique[bx].d_in2_sub_cumh[ei_new];
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
            pos_ori = ei_new;
            sum = 0;
            for(position = pos_ori; position < pos_ori+common.in2_sub_cumh_elem; position = position + common.in2_sub_cumh_rows){
                unique[bx].d_in2_sub_cumh[position] = unique[bx].d_in2_sub_cumh[position] + sum;
                sum = unique[bx].d_in2_sub_cumh[position];
            }
        }

        for(ei_new = 0; ei_new < common.in2_sub_cumh_sel_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub_cumh_sel_rows - 1;
            col = (ei_new+1) / common.in2_sub_cumh_sel_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub_cumh_sel_rows == 0){
                row = common.in2_sub_cumh_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            unique[bx].d_in2_sub_cumh_sel[ei_new] = unique[bx].d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            row = (ei_new+1) % common.in2_sub2_rows - 1;
            col = (ei_new+1) / common.in2_sub2_rows + 1 - 1;
            if((ei_new+1) % common.in2_sub2_rows == 0){
                row = common.in2_sub2_rows - 1;
                col = col-1;
            }

            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            unique[bx].d_in2_sqr_sub2[ei_new] = unique[bx].d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            unique[bx].d_in2_sqr_sub2[ei_new] = unique[bx].d_in2_sub_cumh_sel[ei_new] - unique[bx].d_in2_sqr_sub2[ei_new];
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            temp = unique[bx].d_in2_sub2[ei_new];
            temp2 = unique[bx].d_in2_sqr_sub2[ei_new] - (temp * temp / common.in_elem);
            if(0 > temp2){
                temp2 = 0;
            }
            unique[bx].d_in2_sqr_sub2[ei_new] = sqrt(temp2);
        }

        for(ei_new = 0; ei_new < common.in_sqr_elem; ei_new++) {
            temp = d_in[ei_new];
            unique[bx].d_in_sqr[ei_new] = temp * temp;
        }

        for(ei_new = 0; ei_new < common.in_cols; ei_new++) {
            sum = 0;
            for(i = 0; i < common.in_rows; i++){
                sum = sum + d_in[ei_new*common.in_rows+i];
            }
            in_partial_sum[ei_new] = sum;
        }

        for(ei_new = 0; ei_new < common.in_sqr_rows; ei_new++) {
            sum = 0;
            for(i = 0; i < common.in_sqr_cols; i++){
                sum = sum + unique[bx].d_in_sqr[ei_new+common.in_sqr_rows*i];
            }
            in_sqr_partial_sum[ei_new] = sum;
        }

        in_final_sum = 0;
        for(i = 0; i<common.in_cols; i++){
            in_final_sum = in_final_sum + in_partial_sum[i];
        }

        in_sqr_final_sum = 0;
        for(i = 0; i<common.in_sqr_cols; i++){
            in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
        }

        mean = in_final_sum / common.in_elem;
        mean_sqr = mean * mean;
        variance  = (in_sqr_final_sum / common.in_elem) - mean_sqr;
        deviation = sqrt(variance);

        denomT = sqrt((float)(common.in_elem-1))*deviation;

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            unique[bx].d_in2_sqr_sub2[ei_new] = unique[bx].d_in2_sqr_sub2[ei_new] * denomT;
        }

        for(ei_new = 0; ei_new < common.conv_elem; ei_new++) {
            unique[bx].d_conv[ei_new] = unique[bx].d_conv[ei_new] - unique[bx].d_in2_sub2[ei_new] * in_final_sum / common.in_elem;
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            unique[bx].d_in2_sqr_sub2[ei_new] = unique[bx].d_conv[ei_new] / unique[bx].d_in2_sqr_sub2[ei_new];
        }

        cent = common.sSize + common.tSize + 1;
        if(common_change.frame_no == 0){
            tMask_row = cent + unique[bx].d_Row[unique[bx].point_no] - unique[bx].d_Row[unique[bx].point_no] - 1;
            tMask_col = cent + unique[bx].d_Col[unique[bx].point_no] - unique[bx].d_Col[unique[bx].point_no] - 1;
        }
        else{
            pointer = common_change.frame_no-1+unique[bx].point_no*common.no_frames;
            tMask_row = cent + unique[bx].d_tRowLoc[pointer] - unique[bx].d_Row[unique[bx].point_no] - 1;
            tMask_col = cent + unique[bx].d_tColLoc[pointer] - unique[bx].d_Col[unique[bx].point_no] - 1;
        }

        for(ei_new = 0; ei_new < common.tMask_elem; ei_new++) {
            location = tMask_col*common.tMask_rows + tMask_row;
            if(location == ei_new){
                unique[bx].d_tMask[ei_new] = 1;
            }
            else{
                unique[bx].d_tMask[ei_new] = 0;
            }
        }

        for(ei_new = 0; ei_new < common.mask_conv_elem; ei_new++) {
            ic = (ei_new+1) % common.mask_conv_rows;
            jc = (ei_new+1) / common.mask_conv_rows + 1;
            if((ei_new+1) % common.mask_conv_rows == 0){
                ic = common.mask_conv_rows;
                jc -= 1;
            }

            j = jc + common.mask_conv_joffset;
            jp1 = j + 1;
            if(common.mask_cols < jp1){
                ja1 = jp1 - common.mask_cols;
            }
            else{
                ja1 = 1;
            }
            if(common.tMask_cols < j){
                ja2 = common.tMask_cols;
            }
            else{
                ja2 = j;
            }

            i = ic + common.mask_conv_ioffset;
            ip1 = i + 1;

            if(common.mask_rows < ip1){
                ia1 = ip1 - common.mask_rows;
            }
            else{
                ia1 = 1;
            }
            if(common.tMask_rows < i){
                ia2 = common.tMask_rows;
            }
            else{
                ia2 = i;
            }

            s = 0;

            for(ja=ja1; ja2 >= ja; ja++){
                jb = jp1 - ja;
                for(ia=ia1; ia<=ia2; ia++){
                    ib = ip1 - ia;
                    s = s + unique[bx].d_tMask[common.tMask_rows*(ja-1)+ia-1] * 1;
                }
            }

            unique[bx].d_mask_conv[ei_new] = unique[bx].d_in2_sqr_sub2[ei_new] * s;
        }

        for(ei_new = 0; ei_new < common.mask_conv_rows; ei_new++) {
            largest_value = 0;
            largest_coordinate = 0;
            for(i=0; i<common.mask_conv_cols; i++){
                largest_coordinate_current = ei_new*common.mask_conv_rows+i;
                largest_value_current = abs(unique[bx].d_mask_conv[largest_coordinate_current]);
                if(largest_value < largest_value_current){
                    largest_coordinate = largest_coordinate_current;
                    largest_value = largest_value_current;
                }
            }
            par_max_coo[ei_new] = largest_coordinate;
            par_max_val[ei_new] = largest_value;
        }

        fin_max_val = 0;
        fin_max_coo = 0;
        for(i = 0; i < common.mask_conv_rows; i++){
            if(fin_max_val < par_max_val[i]){
                fin_max_val = par_max_val[i];
                fin_max_coo = par_max_coo[i];
            }
        }

        largest_row = (fin_max_coo+1) % common.mask_conv_rows - 1;
        largest_col = (fin_max_coo+1) / common.mask_conv_rows;
        if((fin_max_coo+1) % common.mask_conv_rows == 0){
            largest_row = common.mask_conv_rows - 1;
            largest_col -= 1;
        }

        largest_row = largest_row + 1;
        largest_col += 1;
        offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
        offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
        pointer = common_change.frame_no+unique[bx].point_no*common.no_frames;
        unique[bx].d_tRowLoc[pointer] = unique[bx].d_Row[unique[bx].point_no] + offset_row;
        unique[bx].d_tColLoc[pointer] = unique[bx].d_Col[unique[bx].point_no] + offset_col;
    }

    if(common_change.frame_no != 0 && (common_change.frame_no)%10 == 0){
        loc_pointer = unique[bx].point_no*common.no_frames+common_change.frame_no;
        unique[bx].d_Row[unique[bx].point_no] = unique[bx].d_tRowLoc[loc_pointer];
        unique[bx].d_Col[unique[bx].point_no] = unique[bx].d_tColLoc[loc_pointer];

        d_in = &unique[bx].d_T[unique[bx].in_pointer];
        for(ei_new = 0; ei_new < common.in_elem; ei_new++) {
            row = (ei_new+1) % common.in_rows - 1;
            col = (ei_new+1) / common.in_rows + 1 - 1;
            if((ei_new+1) % common.in_rows == 0){
                row = common.in_rows - 1;
                col -= 1;
            }

            ori_row = unique[bx].d_Row[unique[bx].point_no] - 25 + row - 1;
            ori_col = unique[bx].d_Col[unique[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col*common.frame_rows+ori_row;

            d_in[ei_new] = common.alpha*d_in[ei_new] + (1.00-common.alpha)*common_change.d_frame[ori_pointer];
        }
    }
}

void write_data(	char* filename,
			int frameNo,
			int frames_processed,
			int endoPoints,
			int* input_a,
			int* input_b,
			int epiPoints,
			int* input_2a,
			int* input_2b){

	FILE* fid;
	int i,j;

	fid = fopen(filename, "w+");
	if( NULL == fid ){
		printf( "The file was not opened for writing\n" );
		return;
	}

      fprintf(fid, "Total AVI Frames: %d\n", frameNo);	
      fprintf(fid, "Frames Processed: %d\n", frames_processed);	
      fprintf(fid, "endoPoints: %d\n", endoPoints);
      fprintf(fid, "epiPoints: %d", epiPoints);
	for(j=0; frames_processed > j;j++)
	  {
	    fprintf(fid, "\n---Frame %d---",j);
	    fprintf(fid, "\n--endo--\n",j);
	    for(i=0; endoPoints > i; i++){
	      fprintf(fid, "%d\t", input_a[j+i*frameNo]);
	    }
	    fprintf(fid, "\n");
	    for(i=0; endoPoints > i; i++){

	      fprintf(fid, "%d\t", input_b[j+i*frameNo]);
	    }
	    fprintf(fid, "\n--epi--\n",j);
	    for(i=0; epiPoints > i; i++){

	      fprintf(fid, "%d\t", input_2a[j+i*frameNo]);
	    }
	    fprintf(fid, "\n");
	    for(i=0; epiPoints > i; i++){

	      fprintf(fid, "%d\t", input_2b[j+i*frameNo]);
	    }
	  }

	fclose(fid);
}

